from flask import Flask, jsonify, request
from pymemcache.client.base import Client
import json
import time

app = Flask(__name__)
memcache_client = Client(('localhost', 11211))

# Mock database function
def get_user_from_db(user_id):
    # Simulate database delay
    time.sleep(0.1)
    return {"id": user_id, "name": f"User {user_id}", "email": f"user{user_id}@example.com"}

# Mock database function for posts
def get_posts_from_db():
    # Simulate database delay
    time.sleep(0.15)
    return [
        {"id": 1, "title": "Post 1", "content": "Content 1"},
        {"id": 2, "title": "Post 2", "content": "Content 2"}
    ]

# Cache decorator for database queries
def cached_query(ttl=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = f"{func.__name__}:{hash(str(args) + str(kwargs))}"
            cached_result = memcache_client.get(cache_key)
            
            if cached_result:
                return json.loads(cached_result)
            
            result = func(*args, **kwargs)
            memcache_client.set(cache_key, json.dumps(result), expire=ttl)
            return result
        return wrapper
    return decorator

# Cached database functions
@cached_query(ttl=300)
def cached_get_user(user_id):
    return get_user_from_db(user_id)

@cached_query(ttl=600)
def cached_get_posts():
    return get_posts_from_db()

@app.route('/user/<int:user_id>')
def get_user(user_id):
    user = cached_get_user(user_id)
    return jsonify(user)

@app.route('/posts')
def get_posts():
    posts = cached_get_posts()
    return jsonify(posts)

@app.route('/cache/stats')
def cache_stats():
    stats = memcache_client.stats()
    return jsonify(stats)

@app.route('/cache/clear')
def clear_cache():
    memcache_client.flush_all()
    return jsonify({"message": "Cache cleared"})

@app.route('/cache/health')
def cache_health():
    try:
        memcache_client.stats()
        return jsonify({"status": "healthy", "connected": True})
    except Exception as e:
        return jsonify({"status": "unhealthy", "connected": False, "error": str(e)})

if __name__ == '__main__':
    app.run(debug=False)